import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { User, Key, Mail, UserPlus, Info, Sun, Moon, CheckSquare, Square, Lock, ArrowRight } from 'lucide-react';
import AboutModal from './AboutModal';

interface LoginProps {
  onInspectorLogin: () => void;
}

const Login: React.FC<LoginProps> = ({ onInspectorLogin }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [isSignUp, setIsSignUp] = useState(false);
  const [isResetMode, setIsResetMode] = useState(false); // إعادة تفعيل وضع استعادة كلمة المرور
  const [showAboutModal, setShowAboutModal] = useState(false);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('theme');
      if (saved === 'dark' || saved === 'light') return saved;
      return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    }
    return 'light';
  });

  useEffect(() => {
    // تحميل البريد الإلكتروني المحفوظ إذا وجد
    const savedEmail = localStorage.getItem('remembered_email');
    if (savedEmail) {
      setEmail(savedEmail);
      setRememberMe(true);
    }

    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setErrorMsg(null);
    setSuccessMsg(null);

    // Hardcoded Inspector Bypass
    if (email.trim().toLowerCase() === 'aminens21@gmail.com' && password === 'Mof@tich') {
        setTimeout(() => {
            onInspectorLogin();
        }, 500);
        return;
    }

    try {
      if (isSignUp) {
        const { data, error } = await supabase.auth.signUp({
          email: email,
          password: password,
          options: { data: { full_name: fullName } }
        });
        if (error) throw error;

        // التعامل مع "تذكرني" عند التسجيل بنجاح
        if (rememberMe) {
          localStorage.setItem('remembered_email', email);
        } else {
          localStorage.removeItem('remembered_email');
        }

        if (data.user && !data.session) {
           // إذا لم يتم إنشاء جلسة (حتى لو تم تعطيل التأكيد في بعض الحالات)، نعرض رسالة نجاح عامة
           setSuccessMsg("تم إنشاء الحساب بنجاح! يمكنك تسجيل الدخول الآن.");
           setIsSignUp(false);
        }
      } else {
        const { error } = await supabase.auth.signInWithPassword({
          email: email,
          password: password,
        });
        if (error) throw error;

        // التعامل مع "تذكرني" عند الدخول بنجاح
        if (rememberMe) {
          localStorage.setItem('remembered_email', email);
        } else {
          localStorage.removeItem('remembered_email');
        }
      }
