      else if (msg === "User already registered") msg = "هذا البريد الإلكتروني مسجل بالفعل.";
      else if (msg.includes("Email not confirmed")) msg = "البريد الإلكتروني غير مؤكد. إذا قمت بإلغاء الخاصية مؤخراً، يرجى إنشاء حساب جديد.";
      setErrorMsg(msg);
    } finally {
      setIsLoading(false);
    }
  };

  const handleResetPassword = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setErrorMsg(null);
    setSuccessMsg(null);

    try {
      // إرسال رابط لإعادة تعيين كلمة المرور
      const { error } = await supabase.auth.resetPasswordForEmail(email, {
        redirectTo: window.location.origin, // سيعيد التوجيه إلى نفس الصفحة لفتح نافذة التغيير
      });
      if (error) throw error;
      setSuccessMsg("تم إرسال رابط لإنشاء كلمة مرور جديدة إلى بريدك الإلكتروني.");
    } catch (error: any) {
      console.error("Reset error:", error);
      let msg = error.message;
      if (msg.includes("rate limit")) msg = "يرجى الانتظار قليلاً قبل المحاولة مرة أخرى.";
      else msg = "حدث خطأ أثناء إرسال الرابط. تأكد من صحة البريد الإلكتروني.";
      setErrorMsg(msg);
    } finally {
      setIsLoading(false);
    }
  };

