import AboutModal from './components/AboutModal';
import { LogOut, Calendar, Send, CloudOff, RefreshCw, Edit, Info, Sun, Moon, FileText, CheckSquare, Edit2, Settings, Lock, X } from 'lucide-react';
import { supabase } from './services/supabaseClient';

type AppMode = 'login' | 'teacher' | 'inspector' | 'loading';

// تم تحديث بريد المفتش
const INSPECTOR_EMAIL = 'aminens21@gmail.com';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('loading');
  const [user, setUser] = useState<User | null>(null);
  const [sessions, setSessions] = useState<ClassSession[]>([]);
  const [myLicenses, setMyLicenses] = useState<LicenseRecord[]>([]);
  const [isConfirmModalOpen, setIsConfirmModalOpen] = useState(false);
  const [isLicenseModalOpen, setIsLicenseModalOpen] = useState(false);
  const [isOffline, setIsOffline] = useState(false);

  // Settings & Password State
  const [showSettings, setShowSettings] = useState(false);
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [passwordMsg, setPasswordMsg] = useState<{type: 'success'|'error', text: string} | null>(null);
  const [isRecoveryMode, setIsRecoveryMode] = useState(false);

  // Edit Slot Modal State
  const [editModalState, setEditModalState] = useState<{
    isOpen: boolean;
    day: DayOfWeek;
    time: string;
    initialClassName: string;
  }>({ isOpen: false, day: DayOfWeek.MONDAY, time: '08:00', initialClassName: '' });

  // وظيفة لتحديد الثيم التلقائي بناءً على الوقت
  const getAutoTheme = (): 'light' | 'dark' => {
    const hour = new Date().getHours();
    return (hour >= 19 || hour < 6) ? 'dark' : 'light';
  };

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('theme');
      if (saved === 'dark' || saved === 'light') return saved;
      return getAutoTheme();
    }
    return 'light';
  });

  const [showAboutModal, setShowAboutModal] = useState(false);
  const [isEditingProfile, setIsEditingProfile] = useState(false);

  useEffect(() => {
    if (theme === 'dark') document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  // دالة تحميل بيانات المستخدم
  const loadUserData = useCallback(async (userId: string, email: string, metaName?: string) => {
      // Inspector Check
      // مقارنة البريد الإلكتروني لتحديد وضع المفتش
      if (email.toLowerCase() === INSPECTOR_EMAIL.toLowerCase()) {
          setMode('inspector');
          setUser({ 
              id: userId, 
              email: email, 
              name: 'المفتش التربوي', 
              avatarUrl: `https://ui-avatars.com/api/?name=Inspector&background=10b981&color=fff` 
          });
          return;
      }

      // Teacher Data
      const { data: profile } = await supabase.from('profiles').select('*').eq('id', userId).single();
      const { data: detailsData, error: detailsError } = await supabase.from('teacher_details').select('*').eq('id', userId).single();
      const { data: sessionData, error: sessionError } = await supabase.from('timetable_sessions').select('*').eq('user_id', userId);
      const { data: licenseData } = await supabase.from('licenses').select('*').eq('user_id', userId).order('start_date', { ascending: false });

      const localDetailsStr = localStorage.getItem(`teacher_details_${userId}`);
      const localAvatarStr = localStorage.getItem(`avatar_${userId}`);
      const localSessionsStr = localStorage.getItem(`sessions_${userId}`);
      const localAssignedClassesStr = localStorage.getItem(`assigned_classes_${userId}`);

      let finalDetails: TeacherDetails | undefined;
      let finalSessions: ClassSession[] = [];
      let assignedClasses: string[] = [];

      if (localAssignedClassesStr) {
          try { assignedClasses = JSON.parse(localAssignedClassesStr); } catch (e) { assignedClasses = []; }
      }

      if (detailsData) {
            finalDetails = { 
              fullName: detailsData.full_name, 
              paymentId: detailsData.payment_id, 
              recruitmentDate: detailsData.recruitment_date,
              tenureDate: detailsData.tenure_date,
              lastPromotionDate: detailsData.last_promotion_date,
              gradeDate: detailsData.grade_date, 
              genre: detailsData.genre, 
              framework: detailsData.framework, 
              institution: detailsData.institution, 
              school: detailsData.institution, 
              subject: detailsData.subject, 
              grade: detailsData.grade, 
              rank: detailsData.rank, 
              lastInspectionScore: detailsData.last_inspection_score, 
              lastInspectionDate: detailsData.last_inspection_date, 
              inspectorName: detailsData.inspector_name,
              assignedClasses: assignedClasses,
              sector: detailsData.sector || 'public' // Default to public if null
          };
          localStorage.setItem(`teacher_details_${userId}`, JSON.stringify(finalDetails));
          setIsOffline(false);
      } else if (localDetailsStr) {
            finalDetails = JSON.parse(localDetailsStr);
            if (finalDetails) finalDetails.assignedClasses = assignedClasses;
            if (detailsError) setIsOffline(true);
      } else {
            // استخدام metaName إذا كان موجوداً كأولوية أولى
            const initialName = metaName || profile?.full_name || 'أستاذ';

            finalDetails = { 
              fullName: initialName, 
              paymentId: '', 
              recruitmentDate: '', 
              tenureDate: '', 
              genre: 'male', 
              framework: '', 
              institution: '', 
              subject: 'التربية البدنية والرياضية', 
              grade: '', 
              rank: '', 
              lastInspectionScore: '', 
              lastInspectionDate: '', 
              inspectorName: 'سنوسي أمين', 
              assignedClasses: [],
              sector: 'public'
          };
      }

      // تحديد الاسم المعروض: الأولوية للتفاصيل المحفوظة، ثم البروفايل، ثم الاسم من التسجيل (metaName)
      const displayName = finalDetails?.fullName || profile?.full_name || metaName || 'أستاذ';
      const displayAvatar = localAvatarStr || profile?.avatar_url || `https://ui-avatars.com/api/?name=${displayName}&background=random`;

      setUser({ id: userId, email: email, name: displayName, avatarUrl: displayAvatar, details: finalDetails });

      if (sessionData && sessionData.length > 0) {
          finalSessions = sessionData.map((s: any) => ({ 
              id: s.id, 
              day: s.day as DayOfWeek, 
              startTime: s.start_time, 
              endTime: s.end_time, 
              subject: s.subject, 
              className: s.class_name, 
              room: s.room, 
              color: s.color 
          }));
          localStorage.setItem(`sessions_${userId}`, JSON.stringify(finalSessions));
      } else if (localSessionsStr) {
          finalSessions = JSON.parse(localSessionsStr);
          if (sessionError || (sessionData && sessionData.length === 0)) setIsOffline(true);
      }
      setSessions(finalSessions);

      if (licenseData) {
          setMyLicenses(licenseData.map((l: any) => ({
              id: l.id,
              startDate: l.start_date,
              endDate: l.end_date,
              reason: l.reason
          })));
      }

      setMode('teacher');
  }, []);

  useEffect(() => {
    // Initial Session Check
    const initSession = async () => {
        const { data: { session } } = await supabase.auth.getSession();
        if (session?.user) {
            // تمرير الاسم من metatdata
            loadUserData(
                session.user.id, 
                session.user.email || '', 
                session.user.user_metadata?.full_name
            );
        } else {
            setMode('login');
        }
    };
    initSession();

    // Auth State Listener
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
        // Handle Recovery Event specifically
        if (event === 'PASSWORD_RECOVERY') {
            setShowSettings(true);
            setIsRecoveryMode(true);
        }

        if (event === 'SIGNED_IN' || event === 'PASSWORD_RECOVERY') {
            if (session?.user) {
                // تمرير الاسم من metatdata عند تسجيل الدخول الجديد
                loadUserData(
                    session.user.id, 
                    session.user.email || '', 
                    session.user.user_metadata?.full_name
                );
            }
        } else if (event === 'SIGNED_OUT') {
            setMode('login');
            setUser(null);
            setSessions([]);
            setIsOffline(false);
            setShowSettings(false);
            setIsRecoveryMode(false);
        }
    });

    return () => subscription.unsubscribe();
  }, [loadUserData]);

  const handleLogout = async () => { 
      await supabase.auth.signOut();
      // Ensure local state is reset even if Supabase doesn't trigger event (e.g. local inspector login)
      setMode('login');
      setUser(null);
      setSessions([]);
      setIsOffline(false);
      setShowSettings(false);
      setIsRecoveryMode(false);
  };

  // Handler for local admin login bypass
  const handleLocalInspectorLogin = () => {
      setMode('inspector');
      setUser({ 
          id: 'local-inspector-id', 
          email: INSPECTOR_EMAIL, 
          name: 'المفتش التربوي', 
          avatarUrl: `https://ui-avatars.com/api/?name=Inspector&background=10b981&color=fff` 
      });
  };

  const handleUpdatePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newPassword !== confirmPassword) {
        setPasswordMsg({type: 'error', text: 'كلمتا المرور غير متطابقتين'});
        return;
    }

    const { error } = await supabase.auth.updateUser({ password: newPassword });

    if (error) {
        setPasswordMsg({type: 'error', text: error.message});
    } else {
        setPasswordMsg({type: 'success', text: 'تم تحديث كلمة المرور بنجاح'});
        setTimeout(() => {
            setShowSettings(false);
            setIsRecoveryMode(false);
            setNewPassword('');
            setConfirmPassword('');
            setPasswordMsg(null);
        }, 2000);
    }
  };

  const handleSaveDetails = async (details: TeacherDetails, photoUrl?: string) => {
     if (user?.id) {
         if (details.assignedClasses) {
             localStorage.setItem(`assigned_classes_${user.id}`, JSON.stringify(details.assignedClasses));
         }

         try {
             const { error: detailsError } = await supabase.from('teacher_details').upsert({ 
                 id: user.id, 
                 full_name: details.fullName, 
                 payment_id: details.paymentId || null, 
                 recruitment_date: details.recruitmentDate || null,
                 tenure_date: details.tenureDate || null,
                 last_promotion_date: details.lastPromotionDate || null,
                 grade_date: details.gradeDate || null, 
                 genre: details.genre, 
                 framework: details.framework, 
                 institution: details.institution, 
                 subject: details.subject, 
                 grade: details.grade, 
                 rank: details.rank, 
                 last_inspection_score: details.lastInspectionScore, 
                 last_inspection_date: details.lastInspectionDate, 
                 inspector_name: details.inspectorName,
                 sector: details.sector || 'public' // Include sector in save
            });

             if (detailsError) throw detailsError;

             const profileUpdates: any = {
                 id: user.id,
                 full_name: details.fullName,
                 updated_at: new Date().toISOString(),
             };

             if (photoUrl) {
                 profileUpdates.avatar_url = photoUrl;
             }

             const { error: profileError } = await supabase.from('profiles').upsert(profileUpdates);

             if (profileError) throw profileError;

             setUser({ 
                 ...user, 
                 name: details.fullName, 
                 avatarUrl: photoUrl || user.avatarUrl, 
                 details 
             });

             localStorage.setItem(`teacher_details_${user.id}`, JSON.stringify(details));
             if (photoUrl) {
                 localStorage.setItem(`avatar_${user.id}`, photoUrl);
             }

             setIsEditingProfile(false);
             setIsOffline(false);

         } catch (err: any) { 
             console.error("Save error:", err);
             setIsOffline(true); 
             setUser({ ...user, name: details.fullName, avatarUrl: photoUrl || user.avatarUrl, details });
             localStorage.setItem(`teacher_details_${user.id}`, JSON.stringify(details));
             if (photoUrl) localStorage.setItem(`avatar_${user.id}`, photoUrl);
             setIsEditingProfile(false);
             alert("حدث خطأ في الاتصال، تم حفظ المعلومات محلياً.");
         }
     }
  };

  const updateLocalSessions = (userId: string, newSessions: ClassSession[]) => {
      localStorage.setItem(`sessions_${userId}`, JSON.stringify(newSessions));
  };

  const handleToggleSlot = async (day: DayOfWeek, startTime: string) => {
    if (!user?.id) return;
    let newSessions = [...sessions];
    const idx = sessions.findIndex(s => s.day === day && s.startTime === startTime);

    if (idx >= 0) {
        const toRemove = sessions[idx];
        newSessions = sessions.filter((_, i) => i !== idx);
        setSessions(newSessions);
        updateLocalSessions(user.id, newSessions);

        const { error } = await supabase.from('timetable_sessions').delete().eq('id', toRemove.id);
        if (error) {
             console.error("Error deleting session:", error);
             setIsOffline(true);
        }
    }
  };

  const handleEditSlotRequest = (day: DayOfWeek, startTime: string) => {
    const existing = sessions.find(s => s.day === day && s.startTime === startTime);
    let initialName = existing?.className || '';

    if (!existing) {
        const hStart = parseInt(startTime.split(':')[0]);
        const institution = user?.details?.institution || "";
         if (institution.includes('الإعدادية')) {
           if ((day === DayOfWeek.WEDNESDAY || day === DayOfWeek.FRIDAY) && (hStart === 15 || hStart === 16)) {
               initialName = "ASS";
           }
        } else if (institution.includes('التأهيلية')) {
           if (day === DayOfWeek.FRIDAY && (hStart === 15 || hStart === 16 || hStart === 17)) {
               initialName = "ASS";
           }
        }
    }

    setEditModalState({
      isOpen: true,
      day,
      time: startTime,
      initialClassName: initialName
    });
  };

  const handleSaveSlotDetails = async (className: string) => {
    if (!user?.id) return;
    const { day, time } = editModalState;

    let newSessions = [...sessions];
    const existing = newSessions.find(s => s.day === day && s.startTime === time);

    if (existing) {
        const idx = newSessions.findIndex(s => s.id === existing.id);
        newSessions[idx] = { ...existing, className: className };
        setSessions(newSessions);
        updateLocalSessions(user.id, newSessions);

        const { error } = await supabase.from('timetable_sessions').update({ class_name: className }).eq('id', existing.id);
        if (error) {
            console.error("Error updating class name:", error);
            setIsOffline(true);
        }
    } else {
        const [h, m] = time.split(':').map(Number);
        const endTime = `${(h+1).toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`;

        const tempId = `temp-${Date.now()}`;
        const newSession = { 
            id: tempId, 
            day, 
            startTime: time, 
            endTime, 
            subject: "التربية البدنية", 
            className, 
            room: "", 
            color: 'bg-indigo-600' 
        };

        newSessions.push(newSession);
        setSessions(newSessions);

        const { data, error } = await supabase.from('timetable_sessions').insert({ user_id: user.id, day, start_time: time, end_time: endTime, subject: "التربية البدنية", class_name: className, room: "", color: 'bg-indigo-600' }).select().single();

        if (data && !error) {
            const finalSessions = newSessions.map(s => s.id === tempId ? { ...s, id: data.id } : s);
            setSessions(finalSessions);
            updateLocalSessions(user.id, finalSessions);
        } else {
             console.error("Error creating session with name:", error);
             setIsOffline(true);
        }
    }
  };

  const handleSaveLicense = async (record: LicenseRecord) => {
      if (!user?.id) return;
      try {
          const { data, error } = await supabase.from('licenses').insert({
              user_id: user.id,
              start_date: record.startDate,
              end_date: record.endDate,
              reason: record.reason
          }).select().single();

          if (error) throw error;

          if (data) {
             const newLicense: LicenseRecord = {
                 id: data.id,
                 startDate: data.start_date,
                 endDate: data.end_date,
                 reason: data.reason
             };
             setMyLicenses(prev => [newLicense, ...prev]);
          }

          alert(`تم تسجيل الرخصة بنجاح من ${record.startDate} إلى ${record.endDate}. سيتم إشعار السيد المفتش.`);
      } catch (err: any) {
          console.error("Error saving license:", err);
          alert("حدث خطأ أثناء حفظ الرخصة. يرجى التأكد من اتصالك بالإنترنت.");
      }
  };

  if (mode === 'loading') return <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-slate-900"><div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div></div>;
  if (mode === 'login') return <Login onInspectorLogin={handleLocalInspectorLogin} />;
  if (mode === 'inspector') return <InspectorDashboard onLogout={handleLogout} onThemeToggle={toggleTheme} currentTheme={theme} />;
  if (!user) return null;

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-slate-900 flex flex-col transition-colors duration-300" dir="rtl">
      {(!user.details || !user.details.institution || isEditingProfile) ? (
        <TeacherProfileForm user={user} onSave={handleSaveDetails} onLogout={handleLogout} onCancel={user.details?.institution ? () => setIsEditingProfile(false) : undefined} />
      ) : (
        <>
            <header className="bg-white dark:bg-slate-800 shadow-sm border-b border-gray-200 dark:border-slate-700 z-30 sticky top-0 transition-colors">
                {isOffline && (
                    <div className="bg-amber-100 dark:bg-amber-900/40 text-amber-800 dark:text-amber-200 px-4 py-2 text-xs font-bold text-center flex items-center justify-center gap-2 cursor-pointer" onClick={() => window.location.reload()}>
                        <CloudOff className="h-4 w-4" /> وضع غير متصل: البيانات محفوظة محلياً. <RefreshCw className="h-3 w-3 mr-1" />
                    </div>
                )}
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                <div className="flex justify-between items-center h-16">
                    <div className="flex items-center gap-3">
                        <div className="bg-indigo-600 p-2 rounded-lg"><Calendar className="h-6 w-6 text-white" /></div>
                        <div>
                            <h1 className="text-xl font-bold text-gray-900 dark:text-white leading-none">جدول الحصص</h1>
                            <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">أوقات العمل</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-2 sm:gap-4">
                        <button onClick={toggleTheme} className="text-gray-500 dark:text-gray-400 hover:text-indigo-600 p-2 rounded-full hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors" title="تبديل المظهر">
                            {theme === 'dark' ? <Sun className="h-5 w-5" /> : <Moon className="h-5 w-5" />}
                        </button>
                        <button onClick={() => setShowSettings(true)} className="text-gray-500 dark:text-gray-400 hover:text-indigo-600 p-2 rounded-full hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors" title="إعدادات الحساب">
                            <Settings className="h-5 w-5" />
                        </button>
                        <button onClick={() => setShowAboutModal(true)} className="text-gray-500 dark:text-gray-400 hover:text-indigo-600 p-2 rounded-full hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors" title="حول المنصة"><Info className="h-5 w-5" /></button>
                        <button onClick={() => setIsEditingProfile(true)} className="flex items-center gap-2 hover:bg-gray-50 dark:hover:bg-slate-700 p-1.5 rounded-lg transition-colors text-right">
                            <img src={user.avatarUrl} alt="" className="h-8 w-8 rounded-full border dark:border-slate-600 object-cover" />
                            <div className="text-sm hidden sm:block">
                                <p className="font-medium text-gray-700 dark:text-gray-200 flex items-center gap-1">{user.name} <Edit className="h-3 w-3 text-gray-400" /></p>
                            </div>
                        </button>
                        <button onClick={handleLogout} className="text-gray-500 dark:text-gray-400 hover:text-red-600 p-2 rounded-full hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors" title="تسجيل الخروج"><LogOut className="h-5 w-5 transform rotate-180" /></button>
                    </div>
                </div>
                </div>
            </header>

            <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8 flex flex-col">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
                    <div className="w-full md:w-auto">
                        <div className="flex items-center gap-4">
                            <h2 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2">
                                تعديل الجدول
                            </h2>
                            <div className="flex flex-wrap items-center gap-4">
                                <p className="text-sm text-gray-500 dark:text-gray-400 flex items-center gap-1.5 bg-white dark:bg-slate-800 px-3 py-1 rounded-full border border-gray-100 dark:border-slate-700 shadow-sm">
                                    <CheckSquare className="h-3.5 w-3.5 text-indigo-500" />
                                    اضغط المربع للحذف/الإضافة
                                </p>
                                <p className="text-sm text-gray-500 dark:text-gray-400 flex items-center gap-1.5 bg-white dark:bg-slate-800 px-3 py-1 rounded-full border border-gray-100 dark:border-slate-700 shadow-sm">
                                    <Edit2 className="h-3.5 w-3.5 text-indigo-500" />
                                    اضغط الخانة لتعديل الاسم
                                </p>
                           </div>
                        </div>
                    </div>
                    <div className="flex items-center gap-3 w-full md:w-auto mt-4 md:mt-0">
                        <button onClick={() => setIsLicenseModalOpen(true)} className="flex-1 md:flex-none inline-flex items-center justify-center gap-2 px-4 py-2 border border-indigo-200 dark:border-indigo-900/50 text-sm font-medium rounded-md shadow-sm text-indigo-700 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/20 hover:bg-indigo-100 transition-all">
                            <FileText className="h-4 w-4" /> رخصة
                        </button>
                        <button onClick={() => setShowSettings(true)} className="flex-1 md:flex-none inline-flex items-center justify-center gap-2 px-4 py-2 border border-gray-200 dark:border-slate-600 text-sm font-medium rounded-md shadow-sm text-gray-700 dark:text-gray-300 bg-white dark:bg-slate-700 hover:bg-gray-50 dark:hover:bg-slate-600 transition-all">
                            <Lock className="h-4 w-4" /> تغيير القن
                        </button>
                        <button onClick={() => setIsConfirmModalOpen(true)} disabled={sessions.length === 0} className="flex-1 md:flex-none inline-flex items-center justify-center gap-2 px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none transition-all disabled:opacity-50">
                            <Send className="h-4 w-4 transform -scale-x-100" /> تأكيد الجدول
                        </button>
                    </div>
                </div>

                <div className="bg-white dark:bg-slate-800 rounded-xl shadow-lg border border-gray-100 dark:border-slate-700 overflow-hidden transition-all mb-8 ring-2 ring-indigo-500/10">
                    <TimetableGrid 
                      sessions={sessions} 
                      onToggleSlot={handleToggleSlot} 
                      onEditSlot={handleEditSlotRequest}
                      institution={user.details?.institution || ''} 
                    />
                </div>
            </main>

            <footer className="mt-auto py-6 border-t border-gray-100 dark:border-slate-800 bg-white dark:bg-slate-800/50 transition-colors">
                <div className="max-w-7xl mx-auto px-4 text-center space-y-1">
                    <p className="text-sm text-gray-600 dark:text-slate-400 font-medium">تطوير وبرمجة أمين سنوسي مفتش مادة التربية البدنية والرياضية</p>
                    <p className="text-xs text-gray-400 dark:text-slate-500">كل الحقوق محفوظة 2026 &copy;</p>
                </div>
            </footer>
        </>
      )}

      {/* Settings / Change Password Modal */}
      {showSettings && (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/60 backdrop-blur-md">
              <div className="bg-white dark:bg-slate-800 rounded-[2rem] w-full max-w-md p-8 shadow-2xl border border-gray-200 dark:border-slate-700 animate-in zoom-in duration-200 transition-colors">
                  <div className="flex justify-between items-center mb-8">
                      <h3 className="text-xl font-bold flex items-center gap-3 text-gray-900 dark:text-slate-100">
                          <Lock className="h-6 w-6 text-indigo-500" /> 
                          {isRecoveryMode ? 'تغيير كلمة المرور' : 'إعدادات الحساب'}
                      </h3>
                      {!isRecoveryMode && (
                        <button onClick={() => setShowSettings(false)} className="p-2 hover:bg-gray-100 dark:hover:bg-slate-700 rounded-xl text-gray-500 dark:text-slate-400"><X className="h-6 w-6" /></button>
                      )}
                  </div>
                  {isRecoveryMode && (
                      <div className="mb-6 p-3 bg-amber-50 dark:bg-amber-900/20 text-amber-800 dark:text-amber-200 text-sm font-bold rounded-lg border border-amber-200 dark:border-amber-800/50">
                          المرجو إنشاء كلمة مرور جديدة لحسابك.
                      </div>
                  )}
                  <form onSubmit={handleUpdatePassword} className="space-y-6">
                      <div>
                          <label className="text-xs font-bold text-gray-500 dark:text-slate-500 mb-2 block mr-1">كلمة المرور الجديدة</label>
                          <input type="password" required minLength={6} value={newPassword} onChange={e => setNewPassword(e.target.value)} className="w-full px-5 py-3 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-2xl text-sm font-bold text-gray-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none" />
                      </div>
                      <div>
                          <label className="text-xs font-bold text-gray-500 dark:text-slate-500 mb-2 block mr-1">تأكيد كلمة المرور</label>
                          <input type="password" required value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} className="w-full px-5 py-3 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-2xl text-sm font-bold text-gray-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none" />
                      </div>
                      {passwordMsg && <div className={`p-4 rounded-2xl text-xs font-bold border ${passwordMsg.type === 'success' ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 border-emerald-500/20' : 'bg-red-500/10 text-red-600 dark:text-red-400 border-red-500/20'}`}>{passwordMsg.text}</div>}
                      <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-bold rounded-2xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20">تحديث كلمة المرور</button>
                  </form>
              </div>
          </div>
      )}

      <EditSlotModal 
        isOpen={editModalState.isOpen} 
        onClose={() => setEditModalState(prev => ({...prev, isOpen: false}))} 
        onSave={handleSaveSlotDetails}
        day={editModalState.day}
        time={editModalState.time}
        initialClassName={editModalState.initialClassName}
        availableClasses={user?.details?.assignedClasses} 
      />

      <ConfirmationModal isOpen={isConfirmModalOpen} onClose={() => setIsConfirmModalOpen(false)} onConfirm={() => { setIsConfirmModalOpen(false); alert("تم إرسال الجدول بنجاح"); }} title="تأكيد الجدول" message="هل المعلومات صحيحة؟" />
      <LicenseModal isOpen={isLicenseModalOpen} onClose={() => setIsLicenseModalOpen(false)} onSave={handleSaveLicense} />
      <AboutModal isOpen={showAboutModal} onClose={() => setShowAboutModal(false)} />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TeacherProfile } from '../utils/mockData';
import { DayOfWeek, DAYS_ORDER, TIME_SLOTS, ClassSession, LicenseRecord, JS_DAY_MAP } from '../types';
import TimetableGrid from './TimetableGrid';
import EditSlotModal from './EditSlotModal';
import { 
  Filter, UserCheck, UserX, Clock, Calendar, LogOut, Sun, Moon, X, Download, 
  Briefcase, GraduationCap, Award, Building, ClipboardList, User, CreditCard, 
  BookOpen, Settings, MessageCircle, Share2, Lock, Plane, Info, Check, ChevronLeft, ChevronRight, Save, Edit, TrendingUp, AlertTriangle, Search, CheckCircle2, Building2
} from 'lucide-react';
import { utils, writeFile } from 'xlsx';
import { supabase } from '../services/supabaseClient';

interface InspectorDashboardProps {
  onLogout: () => void;
  onThemeToggle: () => void;
  currentTheme: 'light' | 'dark';
}

const InspectorDashboard: React.FC<InspectorDashboardProps> = ({ onLogout, onThemeToggle, currentTheme }) => {
  const [allTeachers, setAllTeachers] = useState<TeacherProfile[]>([]);
  const [allLicenses, setAllLicenses] = useState<LicenseRecord[]>([]);
  const [loading, setLoading] = useState(true);

  // Filter States
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [selectedTime, setSelectedTime] = useState<string>("08:00");
  const [duration, setDuration] = useState<number>(1);
  const [period, setPeriod] = useState<'morning' | 'evening'>(() => {
    const hour = new Date().getHours();
    return (hour >= 12) ? 'evening' : 'morning';
  });

  // Promotion Year State (Default 2024)
  const [promotionYear, setPromotionYear] = useState<number>(2024);

  const [activeFilter, setActiveFilter] = useState<'all' | 'working' | 'available' | 'leave' | 'promotion'>('all');
  const [sectorFilter, setSectorFilter] = useState<'all' | 'public' | 'private'>('all');

  const [showSettings, setShowSettings] = useState(false);
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [passwordMsg, setPasswordMsg] = useState<{type: 'success'|'error', text: string} | null>(null);

  const [viewingTeacher, setViewingTeacher] = useState<TeacherProfile | null>(null);
  const [modifiedSessions, setModifiedSessions] = useState<ClassSession[]>([]);
  const [hasChanges, setHasChanges] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  // Notification State
  const [saveStatus, setSaveStatus] = useState<{type: 'success'|'error', text: string} | null>(null);

  // Edit Details State
  const [isEditingDetails, setIsEditingDetails] = useState(false);
  const [editedDetails, setEditedDetails] = useState<any>({});

  // Edit Modal State for Inspector
  const [editModalState, setEditModalState] = useState<{
    isOpen: boolean;
    day: DayOfWeek;
    time: string;
    initialClassName: string;
  }>({ isOpen: false, day: DayOfWeek.MONDAY, time: '08:00', initialClassName: '' });

  const handleOpenTeacher = (teacher: TeacherProfile) => {
    setViewingTeacher(teacher);
    setModifiedSessions(teacher.sessions); // Initialize local copy
    setHasChanges(false);
    setSaveStatus(null);

    // Initialize Edit Details Form
    setIsEditingDetails(false);
    setEditedDetails({
        fullName: teacher.name,
        paymentId: teacher.details?.paymentId || '',
        recruitmentDate: teacher.details?.recruitmentDate || '',
        tenureDate: teacher.details?.tenureDate || '',
        lastPromotionDate: teacher.details?.lastPromotionDate || '',
        gradeDate: teacher.details?.gradeDate || '',
        genre: teacher.details?.genre || 'male',
        framework: teacher.details?.framework || '',
        institution: teacher.details?.institution || '',
        subject: teacher.details?.subject || '',
        grade: teacher.details?.grade || '',
        rank: teacher.details?.rank || '',
        lastInspectionScore: teacher.details?.lastInspectionScore || '',
        lastInspectionDate: teacher.details?.lastInspectionDate || '',
        inspectorName: teacher.details?.inspectorName || '',
        sector: teacher.details?.sector || 'public'
    });
  };

  const handleCloseTeacher = () => {
    if (hasChanges || isEditingDetails) {
        if (window.confirm("توجد تغييرات غير محفوظة. هل تريد الخروج دون حفظ؟")) {
            setViewingTeacher(null);
            setHasChanges(false);
            setIsEditingDetails(false);
            setSaveStatus(null);
        }
    } else {
        setViewingTeacher(null);
        setSaveStatus(null);
    }
  };

  // Fetch data
  useEffect(() => {
    const fetchData = async () => {
        setLoading(true);
        try {
            const [
              { data: profiles },
              { data: details },
              { data: sessions },
              { data: licenses }
            ] = await Promise.all([
              supabase.from('profiles').select('*'),
              supabase.from('teacher_details').select('*'),
              supabase.from('timetable_sessions').select('*'),
              supabase.from('licenses').select('*')
            ]);

            const mappedLicenses: LicenseRecord[] = (licenses || []).map(l => ({
               id: l.id,
               user_id: l.user_id,
               startDate: l.start_date,
               endDate: l.end_date,
               reason: l.reason
            }));
            setAllLicenses(mappedLicenses);

            const merged: TeacherProfile[] = (profiles || []).map((p: any) => {
                const detail = details?.find((d: any) => d.id === p.id);
                const teacherSessions = (sessions || [])
                    .filter((s: any) => s.user_id === p.id)
                    .map((s: any) => ({
                        id: s.id,
                        day: s.day as DayOfWeek,
                        startTime: s.start_time,
                        endTime: s.end_time,
                        subject: s.subject,
                        className: s.class_name,
                        room: s.room,
                        color: s.color
                    }));

                return {
                    id: p.id,
                    name: detail?.full_name || p.full_name || 'أستاذ',
                    email: p.email,
                    avatarUrl: p.avatar_url,
                    sessions: teacherSessions,
                    details: detail ? {
                        fullName: detail.full_name,
                        paymentId: detail.payment_id,
                        genre: detail.genre,
                        framework: detail.framework,
                        institution: detail.institution,
                        school: detail.institution,
                        subject: detail.subject,
                        grade: detail.grade,
                        rank: detail.rank,
                        recruitmentDate: detail.recruitment_date,
                        tenureDate: detail.tenure_date,
                        lastPromotionDate: detail.last_promotion_date,
                        gradeDate: detail.grade_date, // Added grade_date mapping
                        lastInspectionScore: detail.last_inspection_score,
                        lastInspectionDate: detail.last_inspection_date,
                        inspectorName: detail.inspector_name,
                        sector: detail.sector || 'public' // Map Sector
                    } : undefined
                };
            });

            setAllTeachers(merged);

        } catch (err) {
            console.error("Error fetching data:", err);
        } finally {
            setLoading(false);
        }
    };
    fetchData();
  }, []);

  const currentDayLabel = useMemo(() => {
    const date = new Date(selectedDate);
    const dayIndex = date.getDay();
    // JS days: 0 (Sun) to 6 (Sat)
    return JS_DAY_MAP[dayIndex] || DayOfWeek.MONDAY;
  }, [selectedDate]);

  const getHour = (time: string) => parseInt(time.split(':')[0], 10);

  const isTeacherOnLeave = (teacherId: string, dateStr: string) => {
    const checkDate = new Date(dateStr);
    checkDate.setHours(12,0,0,0);
    return allLicenses.find(license => {
      if (license.user_id !== teacherId) return false;
      const start = new Date(license.startDate);
      const end = new Date(license.endDate);
      start.setHours(0,0,0,0);
      end.setHours(23,59,59,999);
      return checkDate >= start && checkDate <= end;
    });
  };

  // Promotion Eligibility Logic (Based on Tenure Date & Target Year)
  const checkPromotionEligibility = (details: any, targetYear: number) => {
    if (!details?.rank) return { eligible: false, missingTenure: false };

    const currentRank = parseInt(details.rank, 10);
    // Use the specific target year for calculation (End of that year)
    const targetDate = new Date(`${targetYear}-12-31`);

    // Helper to diff years
    const diffYears = (d1: Date, d2: Date) => {
        let years = d2.getFullYear() - d1.getFullYear();
        const m = d2.getMonth() - d1.getMonth();
        if (m < 0 || (m === 0 && d2.getDate() < d1.getDate())) {
            years--;
        }
        return years;
    };

    // Case 1: Rank 1 -> Needs Recruitment Date
    if (currentRank === 1) {
        if (!details.recruitmentDate) return { eligible: false, missingTenure: true, field: 'recruitmentDate' };
        const recDate = new Date(details.recruitmentDate);
        if (isNaN(recDate.getTime())) return { eligible: false, missingTenure: true, field: 'recruitmentDate' };

        const years = diffYears(recDate, targetDate);
        if (years >= 1) return { eligible: true, nextRank: 2, requiredYears: 1 };
        return { eligible: false, missingTenure: false };
    }

    // Case 2: Rank >= 2 -> Needs Tenure Date (Cumulative Calculation)
    if (!details.tenureDate) return { eligible: false, missingTenure: true, field: 'tenureDate' };
    const tenureDate = new Date(details.tenureDate);
    if (isNaN(tenureDate.getTime())) return { eligible: false, missingTenure: true, field: 'tenureDate' };

    const yearsSinceTenure = diffYears(tenureDate, targetDate);

    // Rank durations map (Time to stay IN the rank before moving to next)
    // Rank 1 -> 2: (Calculated separately via recruitment)
    // Rank 2 -> 3: 1 year
    // Rank 3 -> 4: 2 years...
    const rankDurations: {[key: number]: number} = {
        2: 1, 
        3: 2,
        4: 2,
        5: 2,
        6: 2,
        7: 2,
        8: 2,
        9: 2,
        10: 2 
    };

    // Calculate total years needed from Tenure (Rank 2 start) to reach current rank AND complete it
    let totalYearsNeeded = 0;

    // Sum duration of all ranks from 2 up to current
    for (let r = 2; r <= currentRank; r++) {
        totalYearsNeeded += rankDurations[r] || 2;
    }

    if (yearsSinceTenure >= totalYearsNeeded) {
        const nextRank = currentRank + 1;
        const durationOfCurrent = rankDurations[currentRank] || 2;
        return { eligible: true, nextRank, requiredYears: durationOfCurrent };
    }

    return { eligible: false, missingTenure: false };
  };

  const filteredData = useMemo(() => {
    const working: TeacherProfile[] = [];
    const available: TeacherProfile[] = [];
    const onLeave: TeacherProfile[] = [];
    const promotionEligible: TeacherProfile[] = [];

    const filterStart = getHour(selectedTime);
    const filterEnd = filterStart + duration;

    allTeachers.forEach(teacher => {
      // Sector Filter Check
      if (sectorFilter !== 'all') {
          const teacherSector = teacher.details?.sector || 'public';
          if (teacherSector !== sectorFilter) return;
      }

      // Check promotion eligibility
      const promo = checkPromotionEligibility(teacher.details, promotionYear);
      if (promo.eligible) {
          promotionEligible.push(teacher);
      }

      // Check attendance/leave status
      const activeLicense = isTeacherOnLeave(teacher.id, selectedDate);
      if (activeLicense) {
        onLeave.push(teacher);
        return;
      }

      const isWorking = teacher.sessions.some(session => {
        if (session.day !== currentDayLabel) return false;
        const sStart = getHour(session.startTime);
        const sEnd = getHour(session.endTime);
        return sStart < filterEnd && sEnd > filterStart;
      });

      if (isWorking) working.push(teacher);
      else available.push(teacher);
    });

    return { working, available, onLeave, promotionEligible };
  }, [selectedDate, currentDayLabel, selectedTime, duration, allTeachers, allLicenses, promotionYear, sectorFilter]);

  const displayTeachers = useMemo(() => {
    switch (activeFilter) {
      case 'working': return filteredData.working;
      case 'available': return filteredData.available;
      case 'leave': return filteredData.onLeave;
      case 'promotion': return filteredData.promotionEligible;
      default: return [...filteredData.working, ...filteredData.available, ...filteredData.onLeave];
    }
  }, [activeFilter, filteredData]);

  const getStartOfWeek = (date: Date) => {
    const d = new Date(date);
    const day = d.getDay();
    const diff = d.getDate() - day + (day === 0 ? -6 : 1); 
    return new Date(d.setDate(diff));
  };

  const weekDays = useMemo(() => {
    const startOfWeek = getStartOfWeek(new Date(selectedDate));
    return Array.from({ length: 6 }).map((_, i) => {
      const d = new Date(startOfWeek);
      d.setDate(startOfWeek.getDate() + i);
      const iso = d.toISOString().split('T')[0];
      return {
        date: iso,
        dayName: JS_DAY_MAP[d.getDay()],
        shortDate: `${(d.getMonth() + 1).toString().padStart(2, '0')}/${d.getDate().toString().padStart(2, '0')}`
      };
    });
  }, [selectedDate]);

  const changeWeek = (weeks: number) => {
    const newDate = new Date(selectedDate);
    newDate.setDate(newDate.getDate() + (weeks * 7));
    setSelectedDate(newDate.toISOString().split('T')[0]);
  };

  const currentWeekStart = useMemo(() => {
    const start = getStartOfWeek(new Date(selectedDate));
    return start.toLocaleDateString('ar-MA', { day: 'numeric', month: 'short' });
  }, [selectedDate]);

  const handleUpdatePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newPassword !== confirmPassword) { setPasswordMsg({type: 'error', text: 'كلمتا المرور غير متطابقتين'}); return; }
    const { error } = await supabase.auth.updateUser({ password: newPassword });
    if (error) setPasswordMsg({type: 'error', text: error.message});
    else { setPasswordMsg({type: 'success', text: 'تم التحديث بنجاح'}); setNewPassword(''); setConfirmPassword(''); }
  };

  const handleInvite = () => {
    const message = encodeURIComponent(
        "السلام عليكم،\n\nالمرجو من السادة الأساتذة إنشاء حساب جديد في المنصة الرقمية الخاصة بأساتذة التربية البدنية والرياضية، وملء البطاقة المهنية وجدول الحصص بدقة عبر الرابط التالي:\n\nhttps://plateforme-prof-eps.netlify.app/"
    );
    window.open(`https://wa.me/?text=${message}`, '_blank');
  };

  const handleDownloadExcel = () => {
    // Determine which list to export based on filter
    const listToExport = displayTeachers;
    const sheetName = activeFilter === 'promotion' ? `Promotions_${promotionYear}` : 'Teachers';

    const data = listToExport.map(teacher => {
        const promo = checkPromotionEligibility(teacher.details, promotionYear);
        return {
            id: teacher.id,
            fullName: teacher.name,
            employeeId: teacher.details?.paymentId || '',
            rank: teacher.details?.rank || '',
            recruitmentDate: teacher.details?.recruitmentDate || '',
            tenureDate: teacher.details?.tenureDate || '',
            eligibleForPromo: promo.eligible ? 'نعم' : 'لا',
            nextRank: promo.nextRank || '',
            institution: teacher.details?.institution || '',
            sector: teacher.details?.sector === 'private' ? 'خصوصي' : 'عمومي'
        };
    });

    const ws = utils.json_to_sheet(data);
    const wb = utils.book_new();
    utils.book_append_sheet(wb, ws, sheetName);
    writeFile(wb, `${sheetName}.xlsx`);
  };

  // --- Inspector Editing Logic (Local First) ---

  const handleInspectorToggleSlot = (day: DayOfWeek, startTime: string) => {
      const idx = modifiedSessions.findIndex(s => s.day === day && s.startTime === startTime);
      let newSessions = [...modifiedSessions];

      if (idx >= 0) {
          // Remove locally
          newSessions = newSessions.filter((_, i) => i !== idx);
      } else {
          // Add locally
          const [h, m] = startTime.split(':').map(Number);
          const endTime = `${(h + 1).toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`;

          // Auto-fill ASS for green slots
          let defaultClassName = "";
          const institution = viewingTeacher?.details?.institution || "";
          const hStart = parseInt(startTime.split(':')[0]);

          if (institution.includes('الإعدادية')) {
            // Middle School: Wed & Fri 15h, 16h
            if ((day === DayOfWeek.WEDNESDAY || day === DayOfWeek.FRIDAY) && (hStart === 15 || hStart === 16)) {
                defaultClassName = "ASS";
            }
          } else if (institution.includes('التأهيلية')) {
            // High School: Fri 15h, 16h, 17h
            if (day === DayOfWeek.FRIDAY && (hStart === 15 || hStart === 16 || hStart === 17)) {
                defaultClassName = "ASS";
            }
          }

          newSessions.push({ 
              id: `temp-${Date.now()}`, // Temp ID
              day, 
              startTime, 
              endTime, 
              subject: "التربية البدنية", 
              className: defaultClassName, 
              room: "", 
              color: 'bg-indigo-600' 
          });
      }
      setModifiedSessions(newSessions);
      setHasChanges(true);
  };

  const handleInspectorEditSlotRequest = (day: DayOfWeek, startTime: string) => {
    const existing = modifiedSessions.find(s => s.day === day && s.startTime === startTime);
    setEditModalState({
      isOpen: true,
      day,
      time: startTime,
      initialClassName: existing?.className || ''
    });
  };

  const handleInspectorSaveSlot = (className: string) => {
    const { day, time } = editModalState;
    let newSessions = [...modifiedSessions];
    const existing = newSessions.find(s => s.day === day && s.startTime === time);

    if (existing) {
        const idx = newSessions.findIndex(s => s.day === day && s.startTime === time);
        newSessions[idx] = { ...existing, className: className };
    } else {
        const [h, m] = time.split(':').map(Number);
        const endTime = `${(h+1).toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`;
        newSessions.push({ 
             id: `temp-${Date.now()}`,
             day, 
             startTime: time, 
             endTime, 
             subject: "التربية البدنية", 
             className: className, 
             room: "", 
             color: 'bg-indigo-600' 
        });
    }

    setModifiedSessions(newSessions);
    setHasChanges(true);
  };

  // Save DETAILS to DB
  const handleSaveTeacherDetails = async () => {
    if (!viewingTeacher) return;
    setIsSaving(true);
    setSaveStatus(null);

    try {
        const updates = {
            id: viewingTeacher.id, // Explicit ID for upsert
            full_name: editedDetails.fullName,
            payment_id: editedDetails.paymentId,
            recruitment_date: editedDetails.recruitmentDate || null,
            tenure_date: editedDetails.tenureDate || null,
            last_promotion_date: editedDetails.lastPromotionDate || null,
            grade_date: editedDetails.gradeDate || null,
            genre: editedDetails.genre,
            framework: editedDetails.framework,
            institution: editedDetails.institution,
            subject: editedDetails.subject,
            grade: editedDetails.grade,
            rank: editedDetails.rank,
            last_inspection_score: editedDetails.lastInspectionScore,
            last_inspection_date: editedDetails.lastInspectionDate || null,
            inspector_name: editedDetails.inspectorName,
            sector: editedDetails.sector
        };

        const { error } = await supabase
            .from('teacher_details')
            .upsert(updates);

        if (error) throw error;

        // Update profile name as well if changed
        if (editedDetails.fullName !== viewingTeacher.name) {
             await supabase.from('profiles').update({ full_name: editedDetails.fullName }).eq('id', viewingTeacher.id);
        }

        // Update local state
        const updatedTeacher = {
            ...viewingTeacher,
            name: editedDetails.fullName,
            details: { ...viewingTeacher.details, ...editedDetails }
        };

        setAllTeachers(prev => prev.map(t => t.id === viewingTeacher.id ? updatedTeacher : t));
        setViewingTeacher(updatedTeacher);
        setIsEditingDetails(false);
        setSaveStatus({ type: 'success', text: "تم حفظ بيانات الأستاذ بنجاح في قاعدة البيانات." });

        // Auto-hide success message
        setTimeout(() => setSaveStatus(null), 4000);

    } catch (err: any) {
        console.error("Error updating details:", err);
        setSaveStatus({ type: 'error', text: `فشل حفظ البيانات. المرجو المحاولة مرة أخرى.` });
    } finally {
        setIsSaving(false);
    }
  };

  // Save SESSIONS to DB
  const handleSaveChangesToDB = async () => {
    if (!viewingTeacher) return;
    setIsSaving(true);
    setSaveStatus(null);
    const userId = viewingTeacher.id;

    try {
        const { error: deleteError } = await supabase.from('timetable_sessions').delete().eq('user_id', userId);
        if (deleteError) throw new Error(`فشل في حذف الحصص القديمة: ${deleteError.message}`);

        if (modifiedSessions.length > 0) {
            const payload = modifiedSessions.map(s => ({
                user_id: userId,
                day: s.day,
                start_time: s.startTime,
                end_time: s.endTime,
                subject: s.subject || 'التربية البدنية',
                class_name: s.className || '',
                room: s.room || '',
                color: s.color || 'bg-indigo-600'
            }));

            const { error: insertError } = await supabase.from('timetable_sessions').insert(payload);
            if (insertError) throw new Error(`فشل في إضافة الحصص الجديدة: ${insertError.message}`);
        }

        const updatedTeacher = { ...viewingTeacher, sessions: modifiedSessions };
        setAllTeachers(prev => prev.map(t => t.id === userId ? updatedTeacher : t));
        setViewingTeacher(updatedTeacher);
        setHasChanges(false);

        setSaveStatus({ type: 'success', text: "تم حفظ جدول الحصص بنجاح." });
        setTimeout(() => setSaveStatus(null), 4000);

    } catch (error: any) {
        console.error("Error saving sessions:", error);
        setSaveStatus({ type: 'error', text: `حدث خطأ أثناء حفظ الجدول: ${error.message}` });
    } finally {
        setIsSaving(false);
    }
  };

  const handlePromoteTeacher = async () => {
    if (!viewingTeacher?.details?.rank) return;

    const currentRank = parseInt(viewingTeacher.details.rank, 10);
    const nextRank = currentRank + 1;
    // Use the promotion year for the effective date (e.g. 2024-12-31 or 2024-09-01 depending on rules, let's assume end of year for safety or today's date if within year)
    const today = new Date().toISOString().split('T')[0];

    if (!window.confirm(`هل أنت متأكد من ترقية الأستاذ ${viewingTeacher.name} إلى الرتبة ${nextRank}؟`)) return;

    setIsSaving(true);
    setSaveStatus(null);
    try {
        const { error } = await supabase.from('teacher_details').update({
            rank: nextRank.toString(),
            last_promotion_date: today
        }).eq('id', viewingTeacher.id);

        if (error) throw error;

        // Update local state
        const updatedDetails = { ...viewingTeacher.details, rank: nextRank.toString(), lastPromotionDate: today };
        const updatedTeacher = { ...viewingTeacher, details: updatedDetails };

        setAllTeachers(prev => prev.map(t => t.id === viewingTeacher.id ? updatedTeacher : t));
        setViewingTeacher(updatedTeacher);

        // Also update form state if open
        setEditedDetails(prev => ({ ...prev, rank: nextRank.toString(), lastPromotionDate: today }));

        setSaveStatus({ type: 'success', text: `تمت ترقية الأستاذ بنجاح إلى الرتبة ${nextRank}` });
        setTimeout(() => setSaveStatus(null), 4000);
    } catch (err: any) {
        console.error("Promotion error:", err);
        setSaveStatus({ type: 'error', text: "حدث خطأ أثناء الترقية" });
    } finally {
        setIsSaving(false);
    }
  };

  // Helper for rendering inputs
  const renderInput = (key: string, placeholder: string, type = 'text', options?: string[]) => {
    if (options) {
        return (
            <select 
                value={editedDetails[key] || ''}
                onChange={e => setEditedDetails({...editedDetails, [key]: e.target.value})}
                className="w-full bg-white dark:bg-slate-900 border border-gray-300 dark:border-slate-600 rounded-lg px-2 py-1.5 text-xs sm:text-sm font-bold text-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                dir="auto"
            >
                {options.map(opt => <option key={opt} value={opt}>{opt}</option>)}
            </select>
        )
    }
    return (
        <input 
            type={type}
            value={editedDetails[key] || ''}
            onChange={e => setEditedDetails({...editedDetails, [key]: e.target.value})}
            placeholder={placeholder}
            className="w-full bg-white dark:bg-slate-900 border border-gray-300 dark:border-slate-600 rounded-lg px-2 py-1.5 text-xs sm:text-sm font-bold text-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
            dir="auto"
        />
    )
  }

  // Calculate eligibility for current viewing teacher
