             <h2 className="text-2xl font-bold text-gray-900">الملف المهني للأستاذ</h2>
             <p className="mt-2 text-sm text-gray-600">
                {onCancel ? 'تعديل المعلومات المهنية' : 'المرجو إتمام ملء معلوماتكم المهنية للمتابعة'}
