                   {/* Profile Header */}
                   <div className="flex flex-col md:flex-row items-center gap-8 mb-8 bg-gray-50 dark:bg-slate-900/60 rounded-[2.5rem] p-8 border border-gray-200 dark:border-slate-700/50">
