      />

      {/* Footer */}
      <footer className="py-8 bg-white dark:bg-slate-900/50 border-t border-gray-100 dark:border-slate-800/50 text-center transition-colors">
         <p className="text-sm text-gray-500 dark:text-slate-500 font-bold mb-1">تطوير وبرمجة أمين سنوسي مفتش مادة التربية البدنية والرياضية</p>
         <p className="text-[10px] text-gray-400 dark:text-slate-600 font-medium tracking-widest">© 2026 جميع الحقوق محفوظة - نظام الرقابة التربوية الذكية</p>
      </footer>
    </div>
  );
};

export default InspectorDashboard;

payload.text:
السبب الرئيسي لظهور رسالة "تم الحفظ محلياً فقط" هو أن قاعدة البيانات (Supabase) ترفض عملية الكتابة. هذا يحدث عادة لسببين:
1.  **سياسات الأمان (RLS Policies):** قاعدة البيانات مفعلة عليها الحماية ولا توجد "سياسة" تسمح للمستخدم الجديد بإضافة (Insert) بياناته في جدول `teacher_details`.
2.  **نقص في الأعمدة:** قد يكون العمود الجديد `sector` غير موجود في جدول قاعدة البيانات.

لحل مشكلة قاعدة البيانات، يجب عليك تنفيذ كود SQL التالي في لوحة تحكم Supabase (في خانة SQL Editor):

```sql
-- 1. إضافة عمود القطاع إذا لم يكن موجوداً
ALTER TABLE public.teacher_details ADD COLUMN IF NOT EXISTS sector text DEFAULT 'public';

-- 2. تفعيل سياسات الأمان (Row Level Security)
ALTER TABLE public.teacher_details ENABLE ROW LEVEL SECURITY;

-- 3. السماح للمستخدمين بإضافة بياناتهم الخاصة (INSERT)
CREATE POLICY "Enable insert for users based on user_id" ON public.teacher_details FOR INSERT WITH CHECK (auth.uid() = id);

-- 4. السماح للمستخدمين بتعديل بياناتهم الخاصة (UPDATE)
