        setHasChanges(false);

        setSaveStatus({ type: 'success', text: "تم حفظ جدول الحصص بنجاح." });
        setTimeout(() => setSaveStatus(null), 4000);

    } catch (error: any) {
        console.error("Error saving sessions:", error);
        setSaveStatus({ type: 'error', text: `حدث خطأ أثناء حفظ الجدول: ${error.message}` });
    } finally {
        setIsSaving(false);
    }
  };

