DROP POLICY IF EXISTS "Enable all access for owner and inspector" ON timetable_sessions;

-- 2. إنشاء سياسة شاملة (عرض، إضافة، تعديل، حذف)
-- تسمح للأستاذ بالتحكم في بياناته، وتسمح للمفتش بالتحكم في بيانات الجميع
CREATE POLICY "Enable all access for owner and inspector"
ON timetable_sessions
FOR ALL
USING (
  auth.uid() = user_id 
  OR (auth.jwt() ->> 'email') = 'aminens21@gmail.com'
)
WITH CHECK (
  auth.uid() = user_id 
