  full_name TEXT,
  payment_id TEXT,
  genre TEXT,
  framework TEXT,
  institution TEXT,
  subject TEXT,
  grade TEXT,
  rank TEXT,
  last_inspection_score TEXT,
  last_inspection_date TEXT,
  inspector_name TEXT,
  avatar_url text,  -- <<<< هنا يتم تخزين كود الصورة
  created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now())
);

-- 4. Table des Séances (جدول الحصص)
